@typeparam TItem
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="_sentinelRef" class="infinite-scroll-sentinel">
            @if (_isLoading)
            {
                <div class="infinite-scroll-spinner"></div>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter, EditorRequired]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    private ElementReference _sentinelRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? _dotNetRef;
    private bool _isLoading;
    private CancellationTokenSource? _cts;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-a05069f2b2e340b1954d6b9e28f4bfcf/Components/InfiniteScrollList.razor.js");
        }

        if (HasMore && _module is not null)
        {
            await _module.InvokeVoidAsync("observe", _sentinelRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (_isLoading || !HasMore)
            return;

        _isLoading = true;
        StateHasChanged();

        try
        {
            _cts = new CancellationTokenSource();
            await OnLoadMore.InvokeAsync();
        }
        finally
        {
            _isLoading = false;
            _cts?.Dispose();
            _cts = null;
            StateHasChanged();
        }
    }

    public async ValueTask DisposeAsync()
    {
        _cts?.Cancel();
        _cts?.Dispose();

        if (_module is not null)
        {
            try
            {
                await _module.InvokeVoidAsync("disconnect");
                await _module.DisposeAsync();
            }
            catch (JSDisconnectedException)
            {
                // Circuit already gone — safe to ignore.
            }
        }

        _dotNetRef?.Dispose();
    }
}

let observer = null;

export function observe(sentinel, dotNetRef) {
    disconnect();

    observer = new IntersectionObserver((entries) => {
        for (const entry of entries) {
            if (entry.isIntersecting) {
                dotNetRef.invokeMethodAsync("OnSentinelVisible");
            }
        }
    }, {
        rootMargin: "0px 0px 200px 0px"
    });

    observer.observe(sentinel);
}

export function disconnect() {
    if (observer) {
        observer.disconnect();
        observer = null;
    }
}

.infinite-scroll-container {
    overflow-y: auto;
}

.infinite-scroll-sentinel {
    display: flex;
    justify-content: center;
    padding: 1rem;
    min-height: 1px;
}

.infinite-scroll-spinner {
    width: 2rem;
    height: 2rem;
    border: 3px solid rgba(0, 0, 0, 0.1);
    border-top-color: #0d6efd;
    border-radius: 50%;
    animation: infinite-scroll-spin 0.75s linear infinite;
}

@keyframes infinite-scroll-spin {
    to {
        transform: rotate(360deg);
    }
}

